219→    @PostResource(path = "/exportUserWithTeam", requiredPermission = false)
220→    @Operation(summary = "export users with team")
221→    public void exportUserWithTeam(HttpServletRequest request, HttpServletResponse response) throws IOException {
222→        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(SessionContext.getUserId());
223→        if(!checkedSuperManager)
224→            throw new BusinessException(AuthException.UNAUTHORIZED);
225→        setResponseHeader(request, response,"成员列表");
226→        List<ExportMemberWithTeamData> exampleDataList = new ArrayList<>();
227→        List<ExportUserVo> voList = userProjectQueryManager.exportUserWithTeam();
228→        voList.forEach(item -> {
229→            ExportMemberWithTeamData data = new ExportMemberWithTeamData();
230→            data.setTeamName(item.getTeamName());
231→            data.setParentTeamName(item.getParentTeamName());
232→            data.setEmail(item.getEmail());
233→            data.setUserNike(item.getUserNike());
234→            exampleDataList.add(data);
235→        });
236→
237→        List<ExportMemberWithTeamData> viewList = userProjectQueryManager.exportViewUserWithTeam();
238→
239→
240→        ExcelWriter excelWriter = EasyExcel.write(response.getOutputStream())
241→                .excelType(ExcelTypeEnum.XLSX)
242→                .registerWriteHandler(new HeadBgColorFillHandle())
243→                .build();
244→
245→        try {
246→            // 写入第一个sheet
247→            WriteSheet writeSheet1 = EasyExcel.writerSheet(0, "人员清单")
248→                    .head(ExportMemberWithTeamData.class)
249→                    .build();
250→            excelWriter.write(exampleDataList, writeSheet1);
251→
252→            // 写入第二个sheet
253→            WriteSheet writeSheet2 = EasyExcel.writerSheet(1, "可见用户清单") // 或者其他你需要的sheet名称
254→                    .head(ExportMemberWithTeamData.class) // 如果第二个sheet用不同的数据结构，这里改成相应的class
255→                    .build();
256→            excelWriter.write(viewList, writeSheet2);
257→
258→        } finally {
259→            // 写入异常关闭流
260→            if (excelWriter != null) {
261→                excelWriter.finish();
262→            }
263→        }
264→    }
