28→                headWriteCellStyle.setFillForegroundColor(IndexedColors.RED.getIndex());
29→                WriteCellData<?> firstCellData = context.getFirstCellData();
30→                WriteCellStyle.merge(headWriteCellStyle, firstCellData.getOrCreateStyle());
31→            }
